import { useMemo, useState } from 'react';
import { ArrowUpRight, CreditCard, ExternalLink, FileText, RefreshCcw, ShieldCheck, Wallet } from 'lucide-react';
import { PageHeader } from '@/components/layout/PageHeader';
import { Card } from '@/components/ui/Card';
import { Badge } from '@/components/ui/Badge';
import { Button } from '@/components/ui/Button';
import { Select } from '@/components/ui/Select';
import { InlineMessage } from '@/components/feedback/InlineMessage';
import { EmptyState } from '@/components/feedback/EmptyState';
import { ErrorState } from '@/components/feedback/ErrorState';
import { LoadingState } from '@/components/feedback/LoadingState';
import { useBillingPreview, useBillingStatus, useChangePlan, useCreatePaymentLink } from '@/hooks/useBilling';
import { useUiStore } from '@/app/store/ui-store';
import { useAccess } from '@/hooks/useAccess';
import { formatDatetime, toneFromStatus } from '@/utils/format';

const planOptions = [
  { value: 'starter', label: 'Starter' },
  { value: 'professional', label: 'Professional' },
  { value: 'enterprise', label: 'Enterprise' },
];

function normalizeHistory(payload: Record<string, unknown> | undefined) {
  const rows = payload?.payments || payload?.history || payload?.invoices || [];
  return Array.isArray(rows) ? rows : [];
}

export function BillingPage() {
  const canManageBilling = useAccess('billing.manage');
  const billingStatus = useBillingStatus();
  const billingPreview = useBillingPreview();
  const changePlan = useChangePlan();
  const createPaymentLink = useCreatePaymentLink();
  const pushNotification = useUiStore((state) => state.pushNotification);
  const [selectedPlan, setSelectedPlan] = useState('professional');
  const [message, setMessage] = useState<string | null>(null);

  const status = billingStatus.data || {};
  const preview = billingPreview.data || {};
  const paymentHistory = useMemo(() => normalizeHistory(billingPreview.data), [billingPreview.data]);
  const currentPlan = String(status.plan || preview.plan || selectedPlan);

  const summaryRows = [
    { label: 'Status', value: String(status.status || 'Onbekend') },
    { label: 'Actief plan', value: currentPlan },
    { label: 'Volgende factuurdatum', value: formatDatetime(String(status.next_billing_date || preview.next_billing_date || '')) || 'Niet beschikbaar' },
    { label: 'Open seats', value: String(preview.seats || status.seats || '—') },
  ];

  const handlePlanChange = async () => {
    if (!canManageBilling) {
      setMessage('Je hebt geen rechten om billing te beheren.');
      return;
    }
    try {
      await changePlan.mutateAsync({ plan: selectedPlan });
      setMessage(`Abonnement bijgewerkt naar ${selectedPlan}.`);
      pushNotification({ title: 'Abonnement bijgewerkt', description: `Planwijziging naar ${selectedPlan} is via de bestaande API verstuurd.`, tone: 'success' });
    } catch (error) {
      setMessage(error instanceof Error ? error.message : 'Planwijziging mislukt.');
      pushNotification({ title: 'Planwijziging mislukt', description: error instanceof Error ? error.message : 'Onbekende fout', tone: 'error' });
    }
  };

  const handlePaymentLink = async () => {
    if (!canManageBilling) {
      setMessage('Je hebt geen rechten om een betaallink te maken.');
      return;
    }
    try {
      const response = await createPaymentLink.mutateAsync({ plan: selectedPlan });
      const url = String(response.payment_url || response.checkout_url || response.url || '');
      if (url) window.open(url, '_blank', 'noopener,noreferrer');
      setMessage(url ? 'Betaallink geopend in een nieuw tabblad.' : 'Betaallink aangevraagd.');
      pushNotification({ title: 'Betaallink aangemaakt', description: 'De frontend gebruikt alleen veilige payment-link endpoints.', tone: 'success' });
    } catch (error) {
      setMessage(error instanceof Error ? error.message : 'Betaallink maken mislukt.');
      pushNotification({ title: 'Betaallink mislukt', description: error instanceof Error ? error.message : 'Onbekende fout', tone: 'error' });
    }
  };

  return (
    <div className="page-stack">
      <PageHeader title="Billing" description="Abonnement, betaalstatus en planwissels via bestaande tenant- en billing-endpoints." />
      {message ? <InlineMessage tone={message.includes('geen rechten') ? 'danger' : 'success'}>{message}</InlineMessage> : null}

      <div className="kpi-strip">
        {summaryRows.map((row) => (
          <div key={row.label} className="kpi-card">
            <span>{row.label}</span>
            <strong>{row.value}</strong>
          </div>
        ))}
      </div>

      <div className="content-grid-2">
        <Card>
          <div className="section-title-row">
            <h3><CreditCard size={18} /> Subscription overview</h3>
            <div className="inline-end-cluster">
              <Badge tone={toneFromStatus(String(status.status || preview.status || 'neutral'))}>{String(status.status || preview.status || 'Onbekend')}</Badge>
              <Badge tone={canManageBilling ? 'success' : 'warning'}>{canManageBilling ? 'Beheer actief' : 'Alleen lezen'}</Badge>
            </div>
          </div>
          {billingStatus.isLoading ? <LoadingState label="Billingstatus laden..." /> : null}
          {billingStatus.isError ? <ErrorState title="Billingstatus niet geladen" description="Controleer of /tenant/billing/status bereikbaar is." /> : null}
          {!billingStatus.isLoading && !billingStatus.isError ? (
            <div className="detail-grid">
              {summaryRows.map((row) => (
                <div key={row.label}><span>{row.label}</span><strong>{row.value}</strong></div>
              ))}
            </div>
          ) : null}
          <div className="stack-actions" style={{ marginTop: 16 }}>
            <Button variant="secondary" onClick={() => { billingStatus.refetch(); billingPreview.refetch(); }}><RefreshCcw size={16} /> Verversen</Button>
            <Button onClick={handlePaymentLink} disabled={!canManageBilling || createPaymentLink.isPending}><ArrowUpRight size={16} /> Betaallink</Button>
          </div>
        </Card>

        <Card>
          <div className="section-title-row">
            <h3><Wallet size={18} /> Plan wijzigen</h3>
            <Badge tone="neutral">Geen secrets in frontend</Badge>
          </div>
          {!canManageBilling ? <InlineMessage tone="danger">Alleen superadmin kan billing beheren.</InlineMessage> : null}
          <div className="form-grid">
            <label>
              <span>Gewenst plan</span>
              <Select value={selectedPlan} onChange={(event) => setSelectedPlan(event.target.value)} disabled={!canManageBilling}>
                {planOptions.map((option) => <option key={option.value} value={option.value}>{option.label}</option>)}
              </Select>
            </label>
            <label>
              <span>Huidig plan</span>
              <input className="input" value={currentPlan} disabled />
            </label>
            <div className="stack-actions">
              <Button onClick={handlePlanChange} disabled={!canManageBilling || changePlan.isPending}>Plan opslaan</Button>
              <Button variant="secondary" onClick={handlePaymentLink} disabled={!canManageBilling || createPaymentLink.isPending}>Checkout starten</Button>
            </div>
          </div>
        </Card>
      </div>

      <div className="content-grid-2">
        <Card>
          <div className="section-title-row">
            <h3><FileText size={18} /> Billing preview</h3>
          </div>
          {billingPreview.isLoading ? <LoadingState label="Preview laden..." /> : null}
          {billingPreview.isError ? <ErrorState title="Billing preview niet geladen" description="Controleer of /tenant/billing/preview bereikbaar is." /> : null}
          {!billingPreview.isLoading && !billingPreview.isError ? (
            Object.keys(preview).length ? <pre className="code-block">{JSON.stringify(preview, null, 2)}</pre> : <EmptyState title="Geen billing preview" description="Het endpoint gaf nog geen preview-object terug." />
          ) : null}
        </Card>
        <Card>
          <div className="section-title-row">
            <h3><ExternalLink size={18} /> Betaalhistorie</h3>
            <Badge tone="neutral">API data</Badge>
          </div>
          {billingPreview.isLoading ? <LoadingState label="Historie laden..." /> : null}
          {!billingPreview.isLoading && !billingPreview.isError && paymentHistory.length === 0 ? <EmptyState title="Geen betaalhistorie" description="Nog geen invoices of payments beschikbaar in de preview response." /> : null}
          {!billingPreview.isLoading && !billingPreview.isError && paymentHistory.length > 0 ? (
            <div className="list-stack compact-list">
              {paymentHistory.map((row, index) => {
                const record = row as Record<string, unknown>;
                return (
                  <div className="list-row" key={String(record.id || index)}>
                    <div>
                      <strong>{String(record.reference || record.description || `Betaling ${index + 1}`)}</strong>
                      <div className="list-subtle">{formatDatetime(String(record.created_at || record.date || ''))}</div>
                    </div>
                    <div className="inline-end-cluster">
                      <Badge tone={toneFromStatus(String(record.status || 'neutral'))}>{String(record.status || 'Onbekend')}</Badge>
                      <strong>{String(record.amount || record.total || '—')}</strong>
                    </div>
                  </div>
                );
              })}
            </div>
          ) : null}
        </Card>
      </div>
    </div>
  );
}
